import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar: React.FC = () => {
  const { state, logout } = useAuth();
  const navigate = useNavigate();

  // دالة لتنسيق الاسم للعرض
  const formatDisplayName = (firstName: string, lastName: string) => {
    if (!firstName && !lastName) return 'مستخدم';

    // إذا كان الاسم بالعربية، نعرضه كما هو
    if (/[\u0600-\u06FF]/.test(firstName) || /[\u0600-\u06FF]/.test(lastName)) {
      return `${firstName} ${lastName}`.trim();
    }

    // إذا كان بالإنجليزية، نعرضه بشكل منسق
    return `${firstName} ${lastName}`.trim();
  };

  return (
    <nav className="navbar-dark sticky top-0 z-50 backdrop-blur-lg">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          <div className="flex items-center">
            <Link to="/" className="flex items-center space-x-3 group">
              <div className="relative">
                <img 
                  src="/j.png" 
                  alt="Alpha Store" 
                  className="h-10 w-auto transition-transform duration-300 group-hover:scale-105"
                />
              </div>
              <span className="text-white text-xl font-bold hidden sm:block">Alpha Store</span>
            </Link>
          </div>

          <div className="hidden md:flex items-center space-x-6">
            <Link
              to="/"
              className="text-gray-300 hover:text-white px-3 py-2 rounded-md text-sm font-medium transition-colors"
            >
              الرئيسية
            </Link>
            <Link
              to="/cart"
              className="text-gray-300 hover:text-white px-3 py-2 rounded-md text-sm font-medium transition-colors"
            >
              طلباتي
            </Link>

            {state.user ? (
              <>
                {state.user.role === 'admin' && (
                  <Link
                    to="/admin"
                    className="bg-red-600 text-white px-3 py-2 rounded-md text-sm font-medium hover:bg-red-700 transition-colors"
                  >
                    لوحة التحكم
                  </Link>
                )}
                <div className="flex items-center space-x-3">
                  <Link
                    to="/profile"
                    className="text-gray-300 hover:text-white px-3 py-2 rounded-md text-sm font-medium transition-colors"
                  >
                    أهلاً {state.user.firstName}
                  </Link>
                  <button
                    onClick={logout}
                    className="bg-red-600 text-white px-3 py-2 rounded-md text-sm font-medium hover:bg-red-700 transition-colors"
                  >
                    تسجيل خروج
                  </button>
                </div>
              </>
            ) : (
              <div className="flex items-center space-x-3">
                <Link
                  to="/login"
                  className="text-gray-300 hover:text-white px-3 py-2 rounded-md text-sm font-medium transition-colors"
                >
                  تسجيل دخول
                </Link>
                <Link
                  to="/register"
                  className="btn-primary"
                >
                  إنشاء حساب
                </Link>
              </div>
            )}
          </div>

          {/* Mobile menu button */}
          <div className="md:hidden">
            <button className="text-gray-300 hover:text-white p-2">
              <svg className="h-6 w-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
